// 包根 +esm 误选 Node worker 入口；先载入无 worker 的 ELK browser bundle，再动态载入 netlistsvg browser bundle
const el = document.getElementById('schematic'); el.style.cssText = 'height:400px;overflow:auto'; el.textContent = 'Rendering schematic…';
const { default: ELK } = await import('https://cdn.jsdelivr.net/npm/elkjs@0.3.0/lib/elk.bundled.js/+esm'); const previousELK = globalThis.ELK; globalThis.ELK = ELK;
let api; try { api = await import('https://cdn.jsdelivr.net/npm/netlistsvg@1.0.2/built/netlistsvg.bundle.js/+esm'); } finally { if (previousELK === undefined) delete globalThis.ELK; else globalThis.ELK = previousELK; }
const skin = data.skin?.trim().startsWith('<svg') ? data.skin : api.digitalSkin;
api.render(skin, data.netlist, (err, svg) => { if (err) { el.textContent = String(err); return; } el.innerHTML = svg; const s = el.querySelector('svg'); if (s) s.style.maxWidth = 'none'; });

